const navToggle = document.querySelector('.custom-header__menu-toggle');
    const navList = document.querySelector('.nav__list');
    const navList2 = document.querySelector('.nav__list2');
    const navLinks = document.querySelectorAll('.nav__list-link');
    const navLogo = document.querySelectorAll('.custom-header__nav-small-logo');
    navList.setAttribute('aria-expanded', 'true');
    navList2.setAttribute('aria-expanded', 'true');

    navToggle.addEventListener("keypress", function onEvent(event) {
        if (event.key === "Enter") {
            this.setAttribute('aria-expanded', 'true');
            navList.removeAttribute("hidden");
            navList2.removeAttribute("hidden"); 
            //navLogo.removeAttribute("hidden"); 
            navList.setAttribute('aria-expanded', 'true');
            navList2.setAttribute('aria-expanded', 'true');
            document.getElementsByClassName("overlay-close")[0].style.display = "block";
            document.getElementById("custom-header").classList.remove("transparent");
            document.getElementById("menu_toogle").classList.add("open");
            document.getElementsByClassName("custom-header__nav")[0].classList.add("open");
            document.getElementById('firtLi').focus();
        }
    });

    navToggle.addEventListener('keydown', function () {

        if (event.keyCode === 9)//tab
        {
            navToggle.setAttribute('aria-expanded', 'false');
            navList.setAttribute("hidden", true);
            navList2.setAttribute("hidden", true);
        }

        if (event.keyCode === "13")//enter
        {

            this.setAttribute('aria-expanded', 'true');
            navList.removeAttribute("hidden");
            navList2.removeAttribute("hidden");
            navLogo.removeAttribute("hidden");
            navList.setAttribute('aria-expanded', 'true');
            navList2.setAttribute('aria-expanded', 'true');
            document.getElementsByClassName("overlay-close")[0].style.display = "block";
            document.getElementById("custom-header").classList.remove("transparent");
            document.getElementById("menu_toogle").classList.add("open");
            document.getElementsByClassName("custom-header__nav")[0].classList.add("open");
            document.getElementById('firtLi').focus();
        }
    });
    document.addEventListener('keydown', (event) => {
        // Ignore IME composition
        if (event.isComposing || event.keyCode === 229) {
            return;
        }

        // Close menu with ESC key
        if (event.keyCode === 27) {
            if (!navList.hasAttribute('hidden')) {
                navToggle.setAttribute('aria-expanded', 'false');
                navList.setAttribute('hidden', 'true');
                document.getElementsByClassName("overlay-close")[0].style.display = "none";
                document.getElementById("custom-header").classList.add("transparent");
                navList.classList.add("hidden");
                document.getElementById("menu_toogle").classList.remove("open");
                document.getElementsByClassName("custom-header__nav")[0].classList.remove("open");

            }
        }

    });

