$(document).ready(function () {
        var newHeight = 0;
        $('.ULCategories .LICategories').eq(0).addClass('selected');
        $('.inputPageCategoriesHP').addClass('none');
        $('.inputPageCategoriesHP').eq(0).removeClass('none');
        $('.inputPageCategoriesHP').eq(0).addClass('open');

        $('.categoriesCareerHP').css("height", 1100 + "px");

    });
    //CLICKING
    $(function () {
        $('.ULCategories .LICategories').each(function () {
            var $currentNav = $(this);
            var group = $(this).attr('Id');
            $(this).click(function () {
                $('.inputPageCategoriesHP').removeClass('open');
                $('.inputPageCategoriesHP').addClass('none');
                $('.inputPageCategoriesHP').attr('aria-selected','false');

                $('#sub' + group).removeClass('none');
                $('#sub' + group).addClass('open');

                var minHeight = 500;
                var newHeight = Math.abs($('#sub' + group).height());

                newHeight = 1100;

                $('.inputPageCategoriesHP').css("height", (newHeight + 50) + "px");

                $('.ULCategories .LICategories').removeClass('selected');
                $(this).addClass('selected');
            });
            $(this).keyup(function (event) {
                if (event.keyCode === 13) {
                    $(this).click();
                }
            });

        });
    });

$(function () {
        //close all answers
        $('.hiddenDiv').hide();
        var newHeight = 0;


        $('.boxInput').each(function () {
            var group = $(this).attr('Id');
            var $currentItem = $(this);
            var $inner = $('#' + group + ' .inner');

            //click on more link to open
            $('#' + group + ' .more').click(function () {
                var originalHeight = $(this).parent().parent().height();
                var addHeight = originalHeight + $(this).parent().find('.hiddenDiv').height() + 70;

                $(this).parent().parent().parent().parent().css("height", addHeight + "px");
                $('#' + group + ' .hiddenDiv').slideDown('slow');
                $('#' + group + ' .more').hide();
            });

            //click on title link to open
            $('#' + group + ' .jobName').click(function () {
                var originalHeight = $(this).parent().parent().height();
                var addHeight = originalHeight + $(this).parent().find('.hiddenDiv').height() + 70;

                $(this).parent().parent().parent().parent().css("height", addHeight + "px");
                $('#' + group + ' .hiddenDiv').slideDown('slow');
                $('#' + group + ' .more').hide();
            });

            //click on link to close
            $('#' + group + ' .close').click(function () {
                $('#' + group + ' .hiddenDiv').slideUp('slow');
                $('#' + group + ' .more').show();
            });
        });

    });

